@page "/account/login"
@using Microsoft.AspNetCore.Identity
@inject SignInManager<IdentityUser> SignInManager
@inject UserManager<IdentityUser> UserManager
@inject NavigationManager Navigation
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Login</PageTitle>

<div class="row justify-content-center">
    <div class="col-md-4">
        <h3 class="mb-4">Sign In</h3>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <form method="post" @formname="login" @onsubmit="HandleLogin">
            <AntiforgeryToken />

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <input type="email" class="form-control" id="email" @bind="email" required />
            </div>

            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <input type="password" class="form-control" id="password" @bind="password" required />
            </div>

            <input type="hidden" name="returnUrl" value="@returnUrl" />

            <button type="submit" class="btn btn-primary w-100">Login</button>
        </form>
    </div>
</div>

@code {
    [SupplyParameterFromForm] private string? email { get; set; }
    [SupplyParameterFromForm] private string? password { get; set; }
    [SupplyParameterFromForm] private string? returnUrl { get; set; }
    [SupplyParameterFromQuery] private string? ReturnUrl { get; set; }

    private string? errorMessage;

    protected override void OnInitialized()
    {
        returnUrl ??= ReturnUrl ?? "/";
    }

    private async Task HandleLogin()
    {
        if (string.IsNullOrEmpty(email) || string.IsNullOrEmpty(password))
        {
            errorMessage = "Please enter email and password.";
            return;
        }

        var user = await UserManager.FindByEmailAsync(email);
        if (user is null)
        {
            errorMessage = "Invalid email or password.";
            return;
        }

        var result = await SignInManager.PasswordSignInAsync(user, password, isPersistent: false, lockoutOnFailure: false);
        if (result.Succeeded)
        {
            Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }
}

